#include<bits/stdc++.h>
using namespace std;
struct op
{
    long long type,tim,x;
    bool operator<(const op&b)const
    {
        if(tim==b.tim)
        {
            return type>b.type;
        }
        return tim<b.tim;
    }
}a[2000010];
long long dp[2000010];
int main()
{
    long long n,m,k,tot=0;
    scanf("%lld%lld%lld",&n,&m,&k);
    for(long long i=1;i<=n;i++)
    {
        long long l,r,w;
        scanf("%lld%lld%lld",&l,&r,&w);
        l+=k-1;
        if(l>r)
        {
            continue;
        }
        a[++tot]=(op){1,l,w};
        a[++tot]=(op){-1,r+1,w};
    }
    sort(a+1,a+1+tot);
    long long p=1;
    multiset<long long> s;
    for(long long i=k;i<=m;i++)
    {
        while(p<=tot&&a[p].tim<=i)
        {
            if(a[p].type==1)
            {
                s.insert(a[p].x);
            }
            else
            {
                s.erase(s.lower_bound(a[p].x));
            }
            p++;
        }
        dp[i]=dp[i-1];
        if(!s.empty())
        {
            dp[i]=max(dp[i],dp[i-k]+(*s.rbegin()));
        }
    }
    printf("%lld",dp[m]);
    return 0;
}
